  ('bookkeeper-moex-00982', 'bookkeeper', 'bookkeeper-moex-106-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '阪神衣飾向市政府承租攤位，租金$100,000，用以販賣世界大學運動會之紀念服裝，每件進貨成本為 $120，刊登網路廣告花費$50,000，預計可銷售1,000件，若阪神衣飾希望賺得稅前淨利$80,000，則 每件紀念服裝應定價：', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:25+00:00", "source_pdf_sha1": "69dbe7191c6b", "answer_pdf_sha1": "960c5b78db01", "source_family": "moex-gov-tw", "moex": {"exam_code": "106180", "c": "602", "s": "1201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "106", "exam_name": "106年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 25, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00983', 'bookkeeper', 'bookkeeper-moex-106-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '財政部所發布之新解釋函令，對於尚未核課確定案件之效力適用情形為何？ 立即完全適用    不可適用 不利於納稅義務人之解釋函令可追溯適用  有利於納稅義務人之解釋函令可追溯適用', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:25+00:00", "source_pdf_sha1": "94033dba30f4", "answer_pdf_sha1": "57df1534c299", "source_family": "moex-gov-tw", "moex": {"exam_code": "106180", "c": "602", "s": "1204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "106", "exam_name": "106年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 1, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00984', 'bookkeeper', 'bookkeeper-moex-106-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '依現行稅捐稽徵法第48條之2的規定，違反稅法規定應處罰鍰之行為，其情節輕微，或漏稅在一定金額 以下者，下列敘述何者正確？ 加計利息    漏稅罰加重 漏稅罰、行為罰部分得減輕或免予處罰  僅行為罰得減輕處罰', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:25+00:00", "source_pdf_sha1": "94033dba30f4", "answer_pdf_sha1": "57df1534c299", "source_family": "moex-gov-tw", "moex": {"exam_code": "106180", "c": "602", "s": "1204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "106", "exam_name": "106年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 2, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00985', 'bookkeeper', 'bookkeeper-moex-106-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '依現行稅捐稽徵法之規定，關於稅捐核課期間之起算，下列敘述何者正確？ 納稅義務人未於規定期間內申報，但無故意以詐欺或其他不正當方法逃漏稅捐者，核課期間為5年 納稅義務人已在規定期間內申報，但故意以不正當方法逃漏稅者，核課期間為7年 納稅義務人已於規定期間內申報，且無故意以詐欺或其他不正當方法逃漏稅捐者，核課期間自規定申 報期間屆滿之翌日起算 納稅義務人未於規定期間內申報，核課期間自申報日起算7年', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:25+00:00", "source_pdf_sha1": "94033dba30f4", "answer_pdf_sha1": "57df1534c299", "source_family": "moex-gov-tw", "moex": {"exam_code": "106180", "c": "602", "s": "1204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "106", "exam_name": "106年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 3, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00986', 'bookkeeper', 'bookkeeper-moex-106-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '依現行稅捐稽徵法之規定，有關租稅保全之規定，下列敘述何者正確？ 納稅義務人顯有隱匿或移轉財產者，稽徵機關得限制納稅義務人強制出境 納稅義務人欠繳應納稅捐者，稽徵機關通知有關機關，不得為財產移轉或設定他項權利 納稅義務人於稅捐法定徵收日期前，申請離境者，稽徵機關得聲請法院就其財產實施假扣押 納稅義務人就其所欠稅款已依破產法規定和解者，稽徵機關得函請內政部警政署限制其出境', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:25+00:00", "source_pdf_sha1": "94033dba30f4", "answer_pdf_sha1": "57df1534c299", "source_family": "moex-gov-tw", "moex": {"exam_code": "106180", "c": "602", "s": "1204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "106", "exam_name": "106年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 4, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00987', 'bookkeeper', 'bookkeeper-moex-106-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '依現行稅捐稽徵法第28條之規定，有關退稅之規定，下列敘述何者正確？ 納稅義務人自行計算錯誤溢繳之稅款，得自發現之日起5年內提出具體證明，申請退還 納稅義務人因稅捐稽徵機關適用法令錯誤，導致溢繳稅款者，納稅義務人得自發現稽徵機關錯誤原因 之日起2年內申請退還 稽徵機關因適用法令錯誤，導致納稅義務人溢繳稅款者，稽徵機關應自知錯誤原因之日起 2 年內查明 退還，其退還稅款不以5年溢繳者為限 納稅義務人自行適用法令錯誤溢繳稅款者，得自知有錯誤原因之日起2年內申請退還5年內溢繳之稅款', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:25+00:00", "source_pdf_sha1": "94033dba30f4", "answer_pdf_sha1": "57df1534c299", "source_family": "moex-gov-tw", "moex": {"exam_code": "106180", "c": "602", "s": "1204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "106", "exam_name": "106年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 5, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00988', 'bookkeeper', 'bookkeeper-moex-106-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '依現行稅捐稽徵法規定，下列何項係屬納稅義務人權利之保護？ 逾期繳納稅捐應加徵之滯納金，以加計15%為上限 核課期間之限制 稅法所規定之租稅優惠，應明定實施年限，並以達成合理之政策目的為限 稅捐之徵收除法律另有規定外，僅優先於普通債權', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:25+00:00", "source_pdf_sha1": "94033dba30f4", "answer_pdf_sha1": "57df1534c299", "source_family": "moex-gov-tw", "moex": {"exam_code": "106180", "c": "602", "s": "1204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "106", "exam_name": "106年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 6, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00989', 'bookkeeper', 'bookkeeper-moex-106-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '李四戶籍設於臺北市，民國106年5月出售位於新北市之土地，李四對於核定之土地增值稅不服，應向 何機關申請復查？ 新北市政府稅捐稽徵處  財政部北區國稅局  財政部臺北國稅局  臺北市政府稅捐稽徵處', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:25+00:00", "source_pdf_sha1": "94033dba30f4", "answer_pdf_sha1": "57df1534c299", "source_family": "moex-gov-tw", "moex": {"exam_code": "106180", "c": "602", "s": "1204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "106", "exam_name": "106年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 7, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00990', 'bookkeeper', 'bookkeeper-moex-106-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '稅捐稽徵人員對納稅義務人之納稅資料，應保密之對象為下列何者？ 納稅義務人之叔叔    納稅義務人之繼承人 納稅義務人授權之代理人  受理納稅義務人訴願案件之機關', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:25+00:00", "source_pdf_sha1": "94033dba30f4", "answer_pdf_sha1": "57df1534c299", "source_family": "moex-gov-tw", "moex": {"exam_code": "106180", "c": "602", "s": "1204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "106", "exam_name": "106年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 8, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00991', 'bookkeeper', 'bookkeeper-moex-106-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '甲公司與乙公司依法合併而另立丙公司，乙公司於合併前應退之稅捐，合併後應由下列何者受領？ 甲公司  乙公司  丙公司  乙公司之股東', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:25+00:00", "source_pdf_sha1": "94033dba30f4", "answer_pdf_sha1": "57df1534c299", "source_family": "moex-gov-tw", "moex": {"exam_code": "106180", "c": "602", "s": "1204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "106", "exam_name": "106年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 9, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL)
